function initOwnerTabs(){const t=document.querySelectorAll(".menu-tabs-container .tab-btn");t.forEach(e=>{e.addEventListener("click",function(e){e.preventDefault(),t.forEach(t=>t.classList.remove("active")),this.classList.add("active"),window.location.href=this.href})})}function initReportFilters(){const t=document.querySelector("select[name='period']");t&&t.addEventListener("change",function(){this.form.submit()})}function initCharts(){if(!window.chartData){var d=document.getElementById("owner-page-data");if(d){try{var p=JSON.parse(d.value||"{}");window.chartData=Array.isArray(p.chartData)?p.chartData:[];}catch(x){window.chartData=[];}}}const t=document.getElementById("chartsContainer");t&&window.chartData&&0!==window.chartData.length?(t.innerHTML="",window.chartData.forEach((e,n)=>{const a=document.createElement("div");a.className="chart-container";const r=document.createElement("h3");r.className="chart-title",r.textContent=e.title;const o=document.createElement("div");o.className="chart-bars";const s=e.values.map(t=>{const e="string"==typeof t?parseFloat(t):t;return"number"!=typeof e||isNaN(e)?0:e}),c=Math.max(...s.filter(t=>t>0),1);e.values.forEach((t,a)=>{const r="string"==typeof t?parseFloat(t):t,s="number"!=typeof r||isNaN(r)?0:r,i=c>0?s/c*100:5,l=e.labels[a]||a+1,d=document.createElement("div");d.className="chart-bar",d.dataset.value=s,d.dataset.label=l,d.style.height=Math.max(i,20)+"%",d.style.backgroundColor=e.color||getDefaultColor(n);const h=document.createElement("span");h.className="chart-bar-value",h.textContent=formatValue(s);const u=document.createElement("span");u.className="chart-bar-label",u.textContent=formatLabel(l),d.appendChild(h),d.appendChild(u),o.appendChild(d)}),a.appendChild(r),a.appendChild(o),t.appendChild(a)}),document.querySelectorAll(".chart-bar").forEach(t=>{t.addEventListener("mouseenter",function(){this.style.transform="translateY(-8px) scale(1.08)",this.style.boxShadow="0 8px 20px rgba(0, 0, 0, 0.25)",this.style.zIndex="10"}),t.addEventListener("mouseleave",function(){this.style.transform="",this.style.boxShadow="",this.style.zIndex=""}),setTimeout(()=>{t.style.opacity="1",t.style.transform="translateY(0)"},100)})):t&&(t.innerHTML="<p>РќРµС‚ РґР°РЅРЅС‹С… РґР»СЏ РїРѕСЃС‚СЂРѕРµРЅРёСЏ РіСЂР°С„РёРєРѕРІ</p>")}function getDefaultColor(t){const e=["#cd1719","#121212","#2c83c2","#4CAF50","#ff9321","#712121","#db3a34","#000000","#555555","#f9f9f9"];return e[t%e.length]}function formatValue(t){return"number"!=typeof t?String(t):t===Math.floor(t)?t.toString():t.toFixed(2)}function formatLabel(t){const e=String(t);return e.length>12?e.substring(0,10)+"...":e}function refreshReport(){const t=new URL(window.location.href),e=t.searchParams.get("report")||"sales",n=t.searchParams.get("period")||"day";fetch(`/api/report?report=${e}&period=${n}`).then(t=>t.json()).then(t=>{updateReportTable(t)}).catch(t=>{console.error("Error refreshing report:",t)})}function updateReportTable(t){}document.addEventListener("DOMContentLoaded",function(){initOwnerTabs(),initReportFilters(),initCharts()});(function(){
  'use strict';

  function parseOwnerData(){
    var node=document.getElementById('owner-page-data');
    if(!node){return;}
    try{
      var payload=JSON.parse(node.value||'{}');
      window.chartData=Array.isArray(payload.chartData)?payload.chartData:[];
      window.currentPeriod=payload.currentPeriod||'day';
      window.currentReport=payload.currentReport||'sales';
      window.rawReportData=Array.isArray(payload.rawReportData)?payload.rawReportData:[];
    }catch(e){
      window.chartData=[];
      window.currentPeriod='day';
      window.currentReport='sales';
      window.rawReportData=[];
    }
  }

  function initOwnerAdminTabs(){
    var btns=document.querySelectorAll('.admin-tabs .admin-tab-btn');
    var panes=document.querySelectorAll('.admin-tab-pane');
    if(!btns.length||!panes.length){return;}
    var key='ownerAdminTab';
    function setTab(id,persist){
      btns.forEach(function(b){b.classList.toggle('active',b.getAttribute('data-tab')===id);});
      panes.forEach(function(p){p.classList.toggle('active',p.id===id);});
      if(persist){try{localStorage.setItem(key,id);}catch(_){}}
    }
    var initial=(function(){
      var active=[].find.call(btns,function(b){return b.classList.contains('active');});
      var fromDom=active?active.getAttribute('data-tab'):null;
      try{return localStorage.getItem(key)||fromDom;}catch(_){return fromDom;}
    })();
    btns.forEach(function(b){b.addEventListener('click',function(){setTab(b.getAttribute('data-tab'),true);});});
    if(initial){setTab(initial,false);}
  }

  function initRoleSaveButtons(){
    var buttons=document.querySelectorAll('.save-role-btn[data-user-id]');
    if(!buttons.length){return;}
    function findSelect(userId,btn){
      var row=btn.closest('tr, .mobile-table-row, .mobile-table-item');
      if(row){
        var s=row.querySelector('.role-select[data-user-id="'+userId+'"]');
        if(s){return s;}
      }
      return document.querySelector('.role-select[data-user-id="'+userId+'"]');
    }
    buttons.forEach(function(btn){
      btn.addEventListener('click',async function(){
        if(btn.dataset.busy==='1'){return;}
        var userId=btn.getAttribute('data-user-id');
        var select=findSelect(userId,btn);
        if(!select){return;}
        var role=select.value;
        var oldText=btn.textContent;
        var csrf=document.querySelector('meta[name="csrf-token"]')?.content||document.querySelector('input[name="csrf_token"]')?.value||'';
        btn.dataset.busy='1';
        btn.disabled=true;
        btn.textContent='РЎРѕС…СЂР°РЅРµРЅРёРµ...';
        try{
          var resp=await fetch('/update_user_role.php',{
            method:'POST',
            headers:{'Content-Type':'application/json','X-Requested-With':'XMLHttpRequest','X-CSRF-Token':csrf},
            credentials:'same-origin',
            body:JSON.stringify({user_id:Number(userId),role:role,csrf_token:csrf})
          });
          var data=null;
          try{data=await resp.json();}catch(_){data=null;}
          if(!resp.ok||!data||data.success!==true){throw new Error((data&&(data.error||data.message))||('HTTP '+resp.status));}
          btn.textContent='РЎРѕС…СЂР°РЅРµРЅРѕ';
          setTimeout(function(){btn.textContent=oldText;},900);
        }catch(err){
          console.error('Role update error:',err);
          btn.textContent=oldText;
          alert('РћС€РёР±РєР° СЃРѕС…СЂР°РЅРµРЅРёСЏ СЂРѕР»Рё: '+err.message);
        }finally{
          btn.dataset.busy='0';
          btn.disabled=false;
        }
      });
    });
  }

  document.addEventListener('DOMContentLoaded',function(){
    parseOwnerData();
    initOwnerAdminTabs();
    initRoleSaveButtons();
  });
})();
(function(){
  'use strict';

  function ownerChartValue(value){
    var num = typeof value === 'string' ? parseFloat(value) : value;
    if (typeof num !== 'number' || isNaN(num)) {
      return String(value);
    }
    var hasFraction = Math.abs(num % 1) > 0.001;
    return new Intl.NumberFormat('ru-RU', {
      minimumFractionDigits: hasFraction ? 2 : 0,
      maximumFractionDigits: hasFraction ? 2 : 0
    }).format(num);
  }

  function ownerChartCountLabel(count){
    var mod10 = count % 10;
    var mod100 = count % 100;
    if (mod10 === 1 && mod100 !== 11) {
      return count + ' период';
    }
    if (mod10 >= 2 && mod10 <= 4 && (mod100 < 12 || mod100 > 14)) {
      return count + ' периода';
    }
    return count + ' периодов';
  }

  function ownerChartTone(hex){
    if (typeof hex !== 'string' || !/^#?[0-9a-fA-F]{6}$/.test(hex)) {
      return '#cd1719';
    }
    var safe = hex.charAt(0) === '#' ? hex.slice(1) : hex;
    var r = parseInt(safe.slice(0, 2), 16);
    var g = parseInt(safe.slice(2, 4), 16);
    var b = parseInt(safe.slice(4, 6), 16);
    var lift = function(channel){ return Math.min(255, Math.round(channel + (255 - channel) * 0.22)); };
    return 'linear-gradient(180deg, rgb(' + lift(r) + ', ' + lift(g) + ', ' + lift(b) + ') 0%, rgb(' + r + ', ' + g + ', ' + b + ') 100%)';
  }

  function renderOwnerChartsV2(){
    var host = document.getElementById('chartsContainer');
    var seriesList = Array.isArray(window.chartData) ? window.chartData : [];
    if (!host) {
      return;
    }
    if (!seriesList.length) {
      host.innerHTML = '<p class="chart-empty">Нет данных для построения графиков</p>';
      return;
    }

    host.innerHTML = '';

    seriesList.forEach(function(series){
      var values = (series.values || []).map(function(raw){
        var num = typeof raw === 'string' ? parseFloat(raw) : raw;
        return typeof num === 'number' && !isNaN(num) ? num : 0;
      });
      var positive = values.filter(function(value){ return value > 0; });
      var max = positive.length ? Math.max.apply(Math, positive) : 1;

      var card = document.createElement('section');
      card.className = 'chart-container';

      var head = document.createElement('div');
      head.className = 'chart-head';

      var titleWrap = document.createElement('div');
      titleWrap.className = 'chart-title-wrap';

      var kicker = document.createElement('p');
      kicker.className = 'chart-kicker';
      kicker.textContent = 'График';

      var title = document.createElement('h3');
      title.className = 'chart-title';
      title.textContent = series.title || 'Показатель';

      titleWrap.appendChild(kicker);
      titleWrap.appendChild(title);

      var meta = document.createElement('div');
      meta.className = 'chart-meta';
      meta.textContent = ownerChartCountLabel((series.labels || []).length || values.length || 0);

      head.appendChild(titleWrap);
      head.appendChild(meta);
      card.appendChild(head);

      var bars = document.createElement('div');
      bars.className = 'chart-bars';

      values.forEach(function(value, index){
        var labelText = (series.labels && series.labels[index]) ? String(series.labels[index]) : String(index + 1);
        var normalized = max > 0 ? value / max * 100 : 0;
        var barHeight = value > 0 ? Math.max(normalized, 18) : 18;

        var group = document.createElement('div');
        group.className = 'chart-bar-group';

        var track = document.createElement('div');
        track.className = 'chart-bar-track';

        var bar = document.createElement('div');
        bar.className = 'chart-bar';
        bar.dataset.value = String(value);
        bar.dataset.label = labelText;
        bar.style.height = barHeight + '%';
        bar.style.background = ownerChartTone(series.color || getDefaultColor(index));
        bar.title = labelText + ': ' + ownerChartValue(value);

        var valueNode = document.createElement('span');
        valueNode.className = 'chart-bar-value';
        valueNode.textContent = ownerChartValue(value);

        var labelNode = document.createElement('span');
        labelNode.className = 'chart-bar-label';
        labelNode.textContent = labelText;

        bar.appendChild(valueNode);
        track.appendChild(bar);
        group.appendChild(track);
        group.appendChild(labelNode);
        bars.appendChild(group);
      });

      card.appendChild(bars);
      host.appendChild(card);
    });
  }

  document.addEventListener('DOMContentLoaded', function(){
    setTimeout(renderOwnerChartsV2, 0);
  });

  window.addEventListener('pageshow', function(){
    setTimeout(renderOwnerChartsV2, 0);
  });
})();
